DROP TABLE IF EXISTS "1_nama_negara" CASCADE;

CREATE TABLE IF NOT EXISTS "1_nama_negara" (
    id SERIAL PRIMARY KEY,
    nama_negara VARCHAR(255) NOT NULL UNIQUE,
    ibukota VARCHAR(255) DEFAULT '',
    jumlah_penduduk BIGINT DEFAULT 0,
    anggaran BIGINT DEFAULT 0,
    latitude NUMERIC,
    longitude NUMERIC,
    kode_negara VARCHAR(3),
    agama VARCHAR(255) DEFAULT 'atheis',
    ideologi VARCHAR(255) DEFAULT 'nasionalisme',
    un_vote INT DEFAULT 0
);


SELECT setval('1_nama_negara_id_seq', 207);
